        import java.text.SimpleDateFormat;  
	      import sailpoint.object.Custom;
        import sailpoint.object.Filter;
        import sailpoint.tools.Util;
        import sailpoint.object.Link;
        import sailpoint.object.QueryOptions;
        
        Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
        List contractorTypes = new ArrayList();
        
       
        if(custom!=null && custom.get("ContractorType") !=null){
        	contractorTypes = custom.get("ContractorType");
        	//comment decache //context.decache(custom);
        }
        Filter empTypeFilter = Filter.in("type", contractorTypes);
        Filter inactiveFilter = Filter.eq("inactive", true);
       	Filter lastnameFilter = Filter.eq("lastname", identityModel.get("lastname"));
        Filter firstnameFilter = Filter.eq("firstname", identityModel.get("firstname"));
        
        Filter ssnFinalFilter = Filter.eq("ssn", identityModel.get("ssn"));
        if(decryptAES(identityModel.get("ssn")) != null){
         	ssnFinalFilter = Filter.or(ssnFinalFilter ,Filter.eq("ssn", decryptAES(identityModel.get("ssn"))));
        }
        else{
          ssnFinalFilter = Filter.or(ssnFinalFilter ,Filter.eq("ssn", encryptAES(identityModel.get("ssn"))));
        }
        

        Filter dobFinalFilter = Filter.eq("dob", identityModel.get("dob"));
        
        if(decryptAES(identityModel.get("dob")) != null){
         	dobFinalFilter = Filter.or(dobFinalFilter ,Filter.eq("dob", decryptAES(identityModel.get("dob"))));
        }
        else{
          dobFinalFilter = Filter.or(dobFinalFilter ,Filter.eq("dob", encryptAES(identityModel.get("dob"))));
        }
        
        Filter endFilter = Filter.and(empTypeFilter, lastnameFilter, firstnameFilter,ssnFinalFilter, dobFinalFilter);
              
        QueryOptions qo = new QueryOptions();
        qo.add(endFilter);
        
        List properties = new ArrayList();
        properties.add("name");
        Iterator iter = context.search(Identity.class, qo, properties);
        
        while(iter.hasNext()) {
        	Object[] currentUser = iter.next();
        
        if(currentUser != null && currentUser.length > 0 && currentUser[0] != null) {
        			matchingUsers.add(currentUser[0]);  
        		}        
        }
        
        if(null != iter){
       		Util.flushIterator(iter);
        }
        
        
        if(null != matchingUsers && !matchingUsers.isEmpty() && matchingUsers.size() == 1){
        	//Setting identityName to partialFormUser - to be used in Clean IdentityModel and Set IdentityName
          identityModel.put("partialFormUser", matchingUsers.get(0));
        }
  
				return matchingUsers;

       import java.text.SimpleDateFormat;  
        import sailpoint.object.Custom;
        import sailpoint.object.Filter;
        import sailpoint.tools.Util;
        import sailpoint.object.Link;
        import sailpoint.object.QueryOptions;

        Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
        List userTypes = new ArrayList();   

        List orderLists = new ArrayList();

        if(custom!=null && custom.get("userTypes") !=null){
        userTypes = custom.get("userTypes");
        //comment decache //context.decache(custom);
        }

        Filter empTypeFilter = Filter.in("type", userTypes);
        Filter lastnameFilter = Filter.eq("lastname", identityModel.get("lastname"));
        Filter firstnameFilter = Filter.eq("firstname", identityModel.get("firstname"));

        Filter ssnFinalFilter = Filter.eq("ssn", identityModel.get("ssn"));
        if(decryptAES(identityModel.get("ssn")) != null){
        ssnFinalFilter = Filter.or(ssnFinalFilter ,Filter.eq("ssn", decryptAES(identityModel.get("ssn"))));
        }
        else{
        ssnFinalFilter = Filter.or(ssnFinalFilter ,Filter.eq("ssn", encryptAES(identityModel.get("ssn"))));
        }


        Filter dobFinalFilter = Filter.eq("dob", identityModel.get("dob"));

        if(decryptAES(identityModel.get("dob")) != null){
        dobFinalFilter = Filter.or(dobFinalFilter ,Filter.eq("dob", decryptAES(identityModel.get("dob"))));
        }
        else{
        dobFinalFilter = Filter.or(dobFinalFilter ,Filter.eq("dob", encryptAES(identityModel.get("dob"))));
        }

        orderLists.add("lastname,ssn,dob");
        orderLists.add("firstname,ssn,dob");
        orderLists.add("lastname,firstname,dob");
        orderLists.add("lastname,ssn,firstname");
        
				List properties = new ArrayList();
        properties.add("name");
				properties.add("displayName");
        properties.add("internalId");

        for(Object orderList : orderLists){    

        StringTokenizer st = new StringTokenizer(orderList,","); 
        Filter finalFilter = empTypeFilter;
        while (st.hasMoreTokens()) { 

        String filterName = st.nextToken();
        if(Util.nullSafeCaseInsensitiveEq("lastname",filterName)){
        finalFilter = finalFilter.and(finalFilter,lastnameFilter);
        }
        else if(Util.nullSafeCaseInsensitiveEq("firstname",filterName)){ 
        finalFilter = finalFilter.and(finalFilter,firstnameFilter);      
        }
        else if(Util.nullSafeCaseInsensitiveEq("ssn",filterName)){
        finalFilter = finalFilter.and(finalFilter,ssnFinalFilter);
        }
        else if(Util.nullSafeCaseInsensitiveEq("dob",filterName)){
        finalFilter = finalFilter.and(finalFilter,dobFinalFilter);
        }             
        }

        QueryOptions qo = new QueryOptions();
        qo.addFilter(finalFilter);    
        

        Iterator iter = context.search(Identity.class, qo, properties);

        while(iter.hasNext()) {
        Object[] currentUser = iter.next();       	
        if(currentUser != null && currentUser[0] != null && currentUser[1] != null && currentUser[2] != null) {
        
        String userString = currentUser[0] +","+currentUser[1]+","+currentUser[2];
       
        partialMatchingUsers.add(userString); 
        }
        }
        
        if(null != iter){
        Util.flushIterator(iter);
        }
        if(null != partialMatchingUsers && !partialMatchingUsers.isEmpty()){       
        break;
        }
        else{
        continue;
        }	
        }  
        
        if(null != partialMatchingUsers && partialMatchingUsers.isEmpty()){
        
        Filter lastnameTransposeFilter = Filter.eq("lastname", identityModel.get("firstname"));
        Filter firstnameTransposeFilter = Filter.eq("firstname", identityModel.get("lastname"));
        
        QueryOptions qoFinal = new QueryOptions();
        qoFinal.add(empTypeFilter, firstnameTransposeFilter, lastnameTransposeFilter, ssnFinalFilter, dobFinalFilter);

        Iterator iterFinal = context.search(Identity.class, qoFinal, properties);

        while(iterFinal.hasNext()) {
        Object[] currentUser = iterFinal.next();       	
        if(currentUser != null && currentUser[0] != null && currentUser[1] != null && currentUser[2] != null) {
        
        String userString = currentUser[0] +","+currentUser[1]+","+currentUser[2];
       
        partialMatchingUsers.add(userString); 
        }
        }
        
        if(null != iterFinal){
        Util.flushIterator(iterFinal);
        }
        }
        
        
         if ( identityModel != null && identityModel.get("dbFields") != null) {
        	identityModel.remove("dbFields");
        }
   

        return partialMatchingUsers;

        import sailpoint.object.Identity;
        import sailpoint.object.EmailOptions;
        import sailpoint.object.EmailTemplate;
        import sailpoint.api.ObjectUtil;

        EmailTemplate template = context.getObjectByName(EmailTemplate.class, "Ascension-EmailTemplate-PartialMatch-Approver");
				
        Identity workgroupID = context.getObjectByName(Identity.class,"PartialMatchContractors");
        List emailRecipientAddresses = ObjectUtil.getEffectiveEmails(context, workgroupID);
        
        Map args = new HashMap();
        
        args.put("identityDisplayName",identityDisplayName);
        args.put("launcher",launcher);
        args.put("identityName",identityName);

        EmailOptions options = new EmailOptions(emailRecipientAddresses, args);

        if(null != options && template !=null){
          context.sendEmailNotification(template,options);
          //comment decache //context.decache(template);
        }

        import java.text.SimpleDateFormat;  

        String name = "";
        String encryptDOB ="";
        String encryptSSN = "";
        String locationID = "";
        String depID = "";
        String businessID ="";
        String locationName = "";
        String depNum = "";
        
        if(null != identityModel){
          if(null != identityModel.get("firstname") && null != identityModel.get("lastname")){
        		name = initialUserName();
            identityModel.put("name",name);
          }

          if(null != identityModel.get("dob" ) && !Util.nullSafeCaseInsensitiveEq(identityModel.get("domain"),"amita")){
            encryptDOB = encryptAES(identityModel.get("dob"));       
            identityModel.put("dob",encryptDOB);
          }
          if(null != identityModel.get("ssn") && !Util.nullSafeCaseInsensitiveEq(identityModel.get("domain"),"amita")){
            encryptSSN = encryptAES(identityModel.get("ssn"));       
            identityModel.put("ssn",encryptSSN);
          }
        	if(null != identityModel.get("isContractorManager")){
        		if(identityModel.get("isContractorManager")){
        			identityModel.put("isContractorManager","true");
        		}
        		else{
        			identityModel.put("isContractorManager","false");
        		}                
          }
        	if(Util.nullSafeCaseInsensitiveEq(identityModel.get("domain"),"amita")){
            if(Util.isNotNullOrEmpty(identityModel.get("buildingId"))){
              locationName = identityModel.get("buildingId");       
              identityModel.put("location",getLocationName(locationName));
        			identityModel.put("locationDescription",getLocationName(locationName));
            }
            if(Util.isNotNullOrEmpty(identityModel.get("departmentNumber"))){
              depNum = identityModel.get("departmentNumber");       
              identityModel.put("department",getDepartmentName(depNum));
            }
        		if(Util.isNotNullOrEmpty(identityModel.get("buildingId")) && Util.isNotNullOrEmpty(identityModel.get("departmentNumber"))){
              locationID = identityModel.get("buildingId");  
        			depID = identityModel.get("departmentNumber");  
              String businessUnit = getBusinessCode(depID,locationID);
              if(Util.isNotNullOrEmpty(businessUnit)){
             		 identityModel.put("businessUnit",getBusinessCode(depID,locationID));
        			}
            }
        		if(Util.isNotNullOrEmpty(identityModel.get("businessUnit"))){
              businessID = identityModel.get("businessUnit");       
              identityModel.put("businessUnitDescription",getBusinessDesc(businessID));
            }
        	}
        }
        return name;

    
          import sailpoint.tools.Util;
          String enableAcc = wfcontext.getVariable("enableAccounts");

          if(Util.isNotNullOrEmpty(enableAcc) && Util.nullSafeCaseInsensitiveEq(enableAcc,"true")){
          return true;      
          }
          return false;

import sailpoint.object.Identity;
if(Util.isNotNullOrEmpty(identityID)){
  Identity idObj = context.getObjectById(Identity.class,identityID);
  if(idObj != null){
		identityName = idObj.getName();
   wfcontext.setVariable("identityName",identityName);
   //comment decache //context.decache(idObj);
  }
}
return identityName;

   			import sailpoint.api.SailPointContext;
        import sailpoint.object.Identity;
        import sailpoint.object.Form;
        import sailpoint.object.Application;
        import sailpoint.tools.Util;
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningPlan.AttributeRequest;
        import sailpoint.object.Custom; 
        import sailpoint.object.Bundle;

        ProvisioningPlan plan = new ProvisioningPlan();
        if(null != planAD){
          plan = planAD;
        }
        
        Identity identityObject = context.getObjectByName(Identity.class, identityName);
        Custom custRole = context.getObjectByName(Custom.class,"Ascension-Custom-AD-DomainMapping");
        String domainAD = null;
 				String ministryAD = null;
        List roleNames = new ArrayList();
        
        if( null != identityObject){
        	domainAD = identityObject.getAttribute("domain");
        	ministryAD = identityObject.getAttribute("ministry");       	
        }
		if(Util.isNotNullOrEmpty(domainAD)){     
        	domainAD = domainConversion(domainAD);
   		}
       
         if (custRole != null && null != custRole.get("DomainOUMapping")) {
          domainMap = custRole.get("DomainOUMapping");
          if(null != domainMap && !domainMap.isEmpty() && null != domainMap.get(domainAD)){ 
          	roleNames = domainMap.get(domainAD).get("RoleName");
          }
          //comment decache //context.decache(custRole);
        } 
        
				if(null != roleNames && !roleNames.isEmpty()){
          ProvisioningPlan.AccountRequest acctRoleReq = new ProvisioningPlan.AccountRequest();
          acctRoleReq.setApplication("IIQ");
          acctRoleReq.setNativeIdentity(identityName);
          acctRoleReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);    
          for (String roleName: roleNames) {
            AttributeRequest attReq = new AttributeRequest(ProvisioningPlan.ATT_IIQ_ASSIGNED_ROLES , ProvisioningPlan.Operation.Add, roleName);
          
            acctRoleReq.add(attReq);                
          }

          plan.add(acctRoleReq);          

          if(null != identityObject){
        		plan.setIdentity(identityObject);
          	//comment decache //context.decache(identityObject);
          }
        }
        return plan;

        import sailpoint.object.Custom;

        
        String identityName = null;
        
        String locationID = "";
        String depID = "";
        String businessID ="";
        String locationName = "";
        String depName = "";
        
        
         if (identityModel != null && identityModel.get("partialFormUser") != null) {
        	String[] name = identityModel.get("partialFormUser").split(",");      
        identityName = name[0];
        	identityModel.put("name",identityName);
        	wfcontext.setVariable("flow","Bulk Update Contractor Identity");
          identityModel.remove("partialFormUser");
          if (identityModel.get("creationCheckbox") != null) {
            identityModel.remove("creationCheckbox");
          }
        	identityModel.put("manualTerm","No");
        } 
        
        if(identityModel != null && Util.nullSafeCaseInsensitiveEq(identityModel.get("domain"),"amita")){
         if(Util.isNotNullOrEmpty(identityModel.get("buildingId"))){
              locationName = identityModel.get("buildingId");       
              identityModel.put("location",getLocationName(locationName));
              identityModel.put("locationDescription",getLocationName(locationName));
            }
            if(Util.isNotNullOrEmpty(identityModel.get("departmentNumber"))){
              depNum = identityModel.get("departmentNumber");       
              identityModel.put("department",getDepartmentName(depNum));
            }
        		if(Util.isNotNullOrEmpty(identityModel.get("buildingId")) && Util.isNotNullOrEmpty(identityModel.get("departmentNumber"))){
              locationID = identityModel.get("buildingId");  
        			depID = identityModel.get("departmentNumber"); 
              String businessUnit = getBusinessCode(depID,locationID);
              if(Util.isNotNullOrEmpty(businessUnit)){
             		 identityModel.put("businessUnit",getBusinessCode(depID,locationID));
        			}
            }
        		if(Util.isNotNullOrEmpty(identityModel.get("businessUnit"))){
              businessID = identityModel.get("businessUnit");       
              identityModel.put("businessUnitDescription",getBusinessDesc(businessID));
            }
        	}
        
        Custom contractorCustom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
        if (contractorCustom != null) {
        	List metadataAttributes = contractorCustom.get("identityModelMetadata");
        	if (metadataAttributes != null && !metadataAttributes.isEmpty()) {
            for(String attr : metadataAttributes) {
              identityModel.remove(attr);
            }
          }
        	//comment decache //context.decache(contractorCustom);
        }
        
        return identityName;

        import sailpoint.api.SailPointContext;
        import sailpoint.object.Identity;
        import sailpoint.tools.Util;
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningPlan.AttributeRequest;
        import sailpoint.object.ProvisioningPlan.Operation;
        
        ProvisioningPlan plan = new ProvisioningPlan();
        Identity identityObject = null; 
        String identityAttribute = null;
      	String formAttribute = null;
              
          
        if(null !=identityName){ 
        	identityObject = context.getObjectByName(Identity.class, identityName);
        
        	if(null != identityObject){ 
        		List attributeList = new ArrayList(identityModel.keySet());        		
        		AccountRequest iiqAcctReq = new AccountRequest();
            iiqAcctReq.setApplication("IIQ");
            iiqAcctReq.setNativeIdentity(identityName);
            iiqAcctReq.setOperation(AccountRequest.Operation.Modify);
						if(null != attributeList && !attributeList.isEmpty()){
              for(String eachAttribute : attributeList) { 
                if(eachAttribute != null && (eachAttribute.equals("ssn") || eachAttribute.equals("dob"))) {
                //handling encrypted attributes separately 

                if (identityObject.getAttribute(eachAttribute) != null  && decryptAES(identityObject.getAttribute(eachAttribute)) != null) {
                  identityAttribute = decryptAES(identityObject.getAttribute(eachAttribute));
                }
                else{
                	identityAttribute = identityObject.getAttribute(eachAttribute);
                }
        
                if (identityModel != null && identityModel.get(eachAttribute) != null && decryptAES(identityModel.get("eachAttribute")) != null) {
                  formAttribute = decryptAES(identityModel.get(eachAttribute));
                }
        		else{
        		  formAttribute = identityModel.get(eachAttribute);
				}
                if (!Util.nullSafeEq(identityAttribute, formAttribute, true)) {
                  iiqAcctReq.add(new AttributeRequest(eachAttribute, ProvisioningPlan.Operation.Set, identityModel.get(eachAttribute)));                
                }
              }
              else 	if ( !Util.nullSafeEq(identityObject.getAttribute(eachAttribute), identityModel.get(eachAttribute), true) ) {                 
                   iiqAcctReq.add(new AttributeRequest(eachAttribute, ProvisioningPlan.Operation.Set, identityModel.get(eachAttribute)));                
                }        
              }	
        		}        	
        
        	if(identityObject.isInactive()){	
       			iiqAcctReq.add(new AttributeRequest("inactive", ProvisioningPlan.Operation.Set, false)); 
        		wfcontext.setVariable("enableAccounts","true");
       		}
            plan.add(iiqAcctReq);
            plan.setIdentity(identityObject);
            //comment decache //context.decache(identityObject);      
        	}
        } 
        return plan;

       import sailpoint.api.SailPointContext;
        import sailpoint.object.Identity;
        import sailpoint.tools.Util;
        import sailpoint.object.Application;
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningPlan.AttributeRequest;
        import sailpoint.object.Custom;  
        import java.util.Iterator;
        import sailpoint.object.Link;
        import sailpoint.object.ProvisioningPlan.Operation;
        import sailpoint.api.PasswordGenerator;
        import sailpoint.object.PasswordPolicy;
        import java.text.Format;
        import java.text.SimpleDateFormat;

        ProvisioningPlan plan = new ProvisioningPlan();
        
                

        Identity identityObject = null;
        String appName = null;
        String accountName = null;
        String appType = null;
        String adExpDate = null;
        String valueCN = null ;
        String activeOU = null;
        String domainAD = null;
 				String ministryAD = null;
        String locationID= null;
        Map domainMap = new HashMap();
        HashMap activeOUMap = new HashMap();
        List listOfAccounts=new ArrayList();
        
        Custom custom = context.getObjectByName(Custom.class,"Ascension-Custom-AD-DomainMapping");
        Custom customApp = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
        
        if(null != identityModel && Util.isNotNullOrEmpty(identityModel.get("ctrexpDt"))){
          adExpDate = getADFormatedDateString(identityModel.get("ctrexpDt"));       	
        }                  
          
        if(null !=identityName){   
        
        	identityObject = context.getObjectByName(Identity.class, identityName);
        
          if(null != identityObject){ 
            domainAD = identityObject.getAttribute("domain");
            ministryAD = identityObject.getAttribute("ministry");  
        		locationID = identityObject.getAttribute("buildingId");
          
        	if(Util.isNotNullOrEmpty(domainAD)){     
        	domainAD = domainConversion(domainAD);
   		}
            if(custom != null && null != custom.get("DomainOUMapping")){
              domainMap = custom.get("DomainOUMapping");              
              //comment decache //context.decache(custom);
            }
        
        if(null != customApp && null != customApp.get("IncludeReenableApplications")){
        listOfAccounts=customApp.get("IncludeReenableApplications");
        }
        	       
          List linksAccount= (List) identityObject.getLinks();        
        	if( null != linksAccount){
          Iterator itrlinksAccount = linksAccount.iterator();
            while (itrlinksAccount.hasNext()){
              Link account = (Link) itrlinksAccount.next();
              ProvisioningPlan.AccountRequest acctReq = new ProvisioningPlan.AccountRequest();
        			ProvisioningPlan.AccountRequest acctReqModify = new ProvisioningPlan.AccountRequest();
        			
              if(null != account  && null != account.getApplication()){
                appName=account.getApplicationName();
                accountName =account.getNativeIdentity();
        				appType = account.getApplication().getType();
        
                  if(Util.isNotNullOrEmpty(appName) && Util.isNotNullOrEmpty(accountName) && Util.isNotNullOrEmpty(appType) && appType.equalsIgnoreCase("Active Directory - Direct") && listOfAccounts.contains(appName)){
        
										
        						String principalName = account.getAttribute("msDS-PrincipalName");
                    String domainofAcc = "";
        
                    if(Util.isNotNullOrEmpty(principalName)){
                    	domainofAcc = getDomain(principalName);
        						}
                                                               

                    if(Util.nullSafeCaseInsensitiveEq(domainofAcc,domainAD)){
        
        						acctReq.setApplication(appName);
                    acctReq.setNativeIdentity(accountName);
                    acctReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Enable);
                    plan.add(acctReq);
        
         
                    if(null != domainMap && !domainMap.isEmpty() && null != domainMap.get(domainAD)){  
                    activeOUMap = domainMap.get(domainAD).get("activeOU");
                    if(null != activeOUMap && !activeOUMap.isEmpty()){
        						if(Util.isNotNullOrEmpty(locationID) && Util.isNotNullOrEmpty(activeOUMap.get(locationID))){
                    activeOU = activeOUMap.get(locationID);
                    }
                    else{
                    activeOU = activeOUMap.get("DEFAULT");
                    }
                    }	
       							}								

                    String password = null;

                    PasswordPolicy policy = context.getObjectByName(PasswordPolicy.class, "AD Default Password Policy"); 

                   
					if(policy!=null)
                    {       
                    password = new PasswordGenerator(context).generatePassword(policy);
                    }        
        							        
        						acctReqModify.setApplication(appName);
                    acctReqModify.setNativeIdentity(accountName);
                    acctReqModify.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);
        
                    List attreqs = new ArrayList();
                    if (!Util.nullSafeCaseInsensitiveEq(identityObject.getStringAttribute("domain"),"AMITA")){
        							if (Util.isNotNullOrEmpty(adExpDate)){
        								attreqs.add(new AttributeRequest("accountExpires", ProvisioningPlan.Operation.Set, adExpDate));
        								description = "";
        							}                      
        						}
        						else if(Util.isNotNullOrEmpty(identityObject.getAttribute("title")) && Util.isNotNullOrEmpty(identityObject.getAttribute("department"))){
           						description = identityObject.getAttribute("title")+" - "+identityObject.getAttribute("department");          
          					}
        
        						attreqs.add(new AttributeRequest("description", ProvisioningPlan.Operation.Set, description));
        
       							 if (Util.isNotNullOrEmpty(password)){
                      attreqs.add(new AttributeRequest("password", ProvisioningPlan.Operation.Set, password));
                     }

                     if (Util.isNotNullOrEmpty(accountName)) 
                     {
                      valueCN= accountName.substring(0, accountName.indexOf("OU=")-1);
										 }

                    if(Util.isNotNullOrEmpty(activeOU)){
                      attreqs.add(new AttributeRequest("AC_NewParent", ProvisioningPlan.Operation.Set, activeOU));
                    }
        
                    if(Util.isNotNullOrEmpty(valueCN)){
                      attreqs.add(new AttributeRequest("AC_NewName", ProvisioningPlan.Operation.Set, valueCN));
                    }
                    acctReqModify.setAttributeRequests(attreqs);
        						plan.add(acctReqModify);
        						}
        						}
                   else if (Util.isNotNullOrEmpty(appName) && Util.isNotNullOrEmpty(accountName)){
                    if(listOfAccounts.contains(appName)){
                      acctReq.setApplication(appName);
                      acctReq.setNativeIdentity(accountName);
                      acctReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Enable);
                      plan.add(acctReq);                    
                    }  
                    }
                  }
                } 
       				 	if(null != itrlinksAccount){
                	Util.flushIterator(itrlinksAccount);
              	} 
        			}                   
            }        		
            plan.setIdentity(identityObject);
            //comment decache //context.decache(identityObject);
        	}
        return plan;

